powerpagecomponent.content:
{
  "copy": "<!-- Last modified Tue Oct 21 12:39PM -->
<!-- Last modified Sat Aug 30 10:04AM -->
<!-- Last modified thu aug 14 8:08pm -->
{% comment %} Data Change Detection System {% endcomment %}

<div class="row sectionBlockLayout text-start" style="display: flex; flex-wrap: wrap; margin: 0px; min-height: auto; padding: 8px;">
  <div class="container" style="display: flex; flex-wrap: wrap;">
    <div class="col-lg-12 columnBlockLayout" style="flex-grow: 1; display: flex; flex-direction: column; min-width: 250px; padding: 16px; margin: 60px 0px;">

      <h1>Data Change Detection System</h1>
      <p>Monitor data changes across multiple tables using hash comparison</p>

      <div class="card" style="margin-bottom: 20px;">
        <div class="card-header">
          <h3>Table Selection</h3>
        </div>
        <div class="card-body">
          <div class="form-check" style="margin-bottom: 10px;">
            <input class="form-check-input" type="checkbox" id="table-lv_lvcompbranch" checked>
            <label class="form-check-label" for="table-lv_lvcompbranch">
              <strong>lv_lvcompbranch</strong> (Branch data: lv_code, lv_name)
            </label>
          </div>
          <div class="form-check" style="margin-bottom: 10px;">
            <input class="form-check-input" type="checkbox" id="table-lv_lvcompperiod" checked>
            <label class="form-check-label" for="table-lv_lvcompperiod">
              <strong>lv_lvcompperiod</strong> (Period data: lv_periodno, lv_name, lv_visibleonweb)
            </label>
          </div>
        </div>
      </div>

      <div class="card" style="margin-bottom: 20px;">
        <div class="card-header">
          <h3>Hash Calculation</h3>
        </div>
        <div class="card-body">
          <button id="calculateHashes" class="btn btn-primary" style="margin-right: 10px;">Calculate Hashes</button>
          <button id="compareHashes" class="btn btn-secondary" style="margin-right: 10px;">Compare with Previous</button>
          <button id="clearStoredHashes" class="btn btn-warning">Clear Stored Hashes</button>
        </div>
      </div>

      <div id="hashResults" class="card" style="display: none;">
        <div class="card-header">
          <h3>Hash Results</h3>
        </div>
        <div class="card-body">
          <div id="hashOutput"></div>
        </div>
      </div>

      <div id="changeDetection" class="card" style="display: none;">
        <div class="card-header">
          <h3>Change Detection Results</h3>
        </div>
        <div class="card-body">
          <div id="changeOutput"></div>
        </div>
      </div>

    </div>
  </div>
</div>

{% comment %} Fetch data for lv_lvcompbranch table {% endcomment %}
{% fetchxml branchHashQuery %}
    <fetch>
        <entity name="lv_lvcompbranch">
            <attribute name="lv_code" />
            <attribute name="lv_name" />
            <order attribute="lv_code" />
        </entity>
    </fetch>
{% endfetchxml %}

{% comment %} Fetch data for lv_lvcompperiod table {% endcomment %}
{% fetchxml periodHashQuery %}
    <fetch>
        <entity name="lv_lvcompperiod">
            <attribute name="lv_periodno" />
            <attribute name="lv_name" />
            <attribute name="lv_visibleonweb" />
            <order attribute="lv_periodno" />
        </entity>
    </fetch>
{% endfetchxml %}

{% comment %} Calculate hash for lv_lvcompbranch {% endcomment %}
{% assign branchRecordCount = branchHashQuery.results.entities.size %}
{% assign branchRecordCountStr = branchRecordCount | append: "" %}
{% assign branchHashInput = branchRecordCountStr | append: ":::" %}
{% for branch in branchHashQuery.results.entities %}
    {% assign code = branch.lv_code | default: "NULL" %}
    {% assign name = branch.lv_name | default: "NULL" %}
    {% assign branchString = code | append: "~~~" | append: name | append: "|||" %}
    {% assign branchHashInput = branchHashInput | append: branchString %}
{% endfor %}
{% assign branchDataHash = branchHashInput | sha256 %}

{% comment %} Calculate hash for lv_lvcompperiod {% endcomment %}
{% assign periodRecordCount = periodHashQuery.results.entities.size %}
{% assign periodRecordCountStr = periodRecordCount | append: "" %}
{% assign periodHashInput = periodRecordCountStr | append: ":::" %}
{% for period in periodHashQuery.results.entities %}
    {% assign periodno = period.lv_periodno | default: "NULL" %}
    {% assign name = period.lv_name | default: "NULL" %}
    {% assign visibleonweb = period.lv_visibleonweb | default: "NULL" %}
    {% assign periodString = periodno | append: "~~~" | append: name | append: "~~~" | append: visibleonweb | append: "|||" %}
    {% assign periodHashInput = periodHashInput | append: periodString %}
{% endfor %}
{% assign periodDataHash = periodHashInput | sha256 %}

<script>
// Store calculated hashes as JavaScript variables
window.DataHashes = {
    'lv_lvcompbranch': {
        hash: '{{ branchDataHash }}',
        recordCount: {{ branchRecordCountStr }},
        columns: ['lv_code', 'lv_name'],
        rawInput: '{{ branchHashInput | escape }}',
        timestamp: new Date().toISOString()
    },
    'lv_lvcompperiod': {
        hash: '{{ periodDataHash }}',
        recordCount: {{ periodRecordCountStr }},
        columns: ['lv_periodno', 'lv_name', 'lv_visibleonweb'],
        rawInput: '{{ periodHashInput | escape }}',
        timestamp: new Date().toISOString()
    }
};

console.log('Data Hashes calculated:', window.DataHashes);

document.addEventListener('DOMContentLoaded', function() {

    // Calculate Hashes button click handler
    document.getElementById('calculateHashes').addEventListener('click', function() {
        displayCurrentHashes();
    });

    // Compare Hashes button click handler
    document.getElementById('compareHashes').addEventListener('click', function() {
        compareWithStoredHashes();
    });

    // Clear Stored Hashes button click handler
    document.getElementById('clearStoredHashes').addEventListener('click', function() {
        clearStoredHashes();
    });

    // Auto-calculate on page load
    displayCurrentHashes();
});

function displayCurrentHashes() {
    let output = '<h4>Current Hash Values</h4>';

    // Check which tables are selected
    const selectedTables = [];
    if (document.getElementById('table-lv_lvcompbranch').checked) {
        selectedTables.push('lv_lvcompbranch');
    }
    if (document.getElementById('table-lv_lvcompperiod').checked) {
        selectedTables.push('lv_lvcompperiod');
    }

    if (selectedTables.length === 0) {
        output += '<p class="text-warning">No tables selected for hash calculation.</p>';
    } else {
        output += '<div class="table-responsive">';
        output += '<table class="table table-striped">';
        output += '<thead><tr><th>Table</th><th>Record Count</th><th>Columns</th><th>Hash (SHA-256)</th><th>Timestamp</th></tr></thead><tbody>';

        selectedTables.forEach(tableName => {
            const tableData = window.DataHashes[tableName];
            if (tableData) {
                output += `<tr>
                    <td><strong>${tableName}</strong></td>
                    <td>${tableData.recordCount}</td>
                    <td>${tableData.columns.join(', ')}</td>
                    <td><code style="font-size: 10px; word-break: break-all;">${tableData.hash}</code></td>
                    <td>${tableData.timestamp}</td>
                </tr>`;
            }
        });

        output += '</tbody></table></div>';

        // Show raw input for debugging (truncated)
        output += '<h5>Raw Hash Input (Debugging)</h5>';
        output += '<div class="alert alert-info">';
        selectedTables.forEach(tableName => {
            const tableData = window.DataHashes[tableName];
            if (tableData) {
                const truncatedInput = tableData.rawInput.length > 200 
                    ? tableData.rawInput.substring(0, 200) + '...' 
                    : tableData.rawInput;
                output += `<p><strong>${tableName}:</strong> <code>${truncatedInput}</code></p>`;
            }
        });
        output += '</div>';
    }

    document.getElementById('hashOutput').innerHTML = output;
    document.getElementById('hashResults').style.display = 'block';
}

function compareWithStoredHashes() {
    let output = '<h4>Change Detection Results</h4>';

    // Check which tables are selected
    const selectedTables = [];
    if (document.getElementById('table-lv_lvcompbranch').checked) {
        selectedTables.push('lv_lvcompbranch');
    }
    if (document.getElementById('table-lv_lvcompperiod').checked) {
        selectedTables.push('lv_lvcompperiod');
    }

    if (selectedTables.length === 0) {
        output += '<p class="text-warning">No tables selected for comparison.</p>';
    } else {
        const changesDetected = [];
        const noChanges = [];
        const noStoredHash = [];

        selectedTables.forEach(tableName => {
            const currentData = window.DataHashes[tableName];
            const storedHash = localStorage.getItem(`dataHash_${tableName}`);
            const storedTimestamp = localStorage.getItem(`dataHashTimestamp_${tableName}`);

            if (!storedHash) {
                noStoredHash.push({
                    table: tableName,
                    currentHash: currentData.hash,
                    recordCount: currentData.recordCount
                });
            } else if (storedHash !== currentData.hash) {
                changesDetected.push({
                    table: tableName,
                    currentHash: currentData.hash,
                    storedHash: storedHash,
                    currentCount: currentData.recordCount,
                    storedTimestamp: storedTimestamp
                });
            } else {
                noChanges.push({
                    table: tableName,
                    hash: currentData.hash,
                    recordCount: currentData.recordCount,
                    storedTimestamp: storedTimestamp
                });
            }
        });

        // Display results
        if (changesDetected.length > 0) {
            output += '<div class="alert alert-warning">';
            output += '<h5>⚠️ Changes Detected!</h5>';
            output += '<table class="table table-sm"><thead><tr><th>Table</th><th>Current Hash</th><th>Previous Hash</th><th>Current Count</th><th>Last Checked</th></tr></thead><tbody>';
            changesDetected.forEach(item => {
                output += `<tr>
                    <td><strong>${item.table}</strong></td>
                    <td><code style="font-size: 10px;">${item.currentHash.substring(0, 16)}...</code></td>
                    <td><code style="font-size: 10px;">${item.storedHash.substring(0, 16)}...</code></td>
                    <td>${item.currentCount}</td>
                    <td>${item.storedTimestamp || 'Unknown'}</td>
                </tr>`;
            });
            output += '</tbody></table></div>';
        }

        if (noChanges.length > 0) {
            output += '<div class="alert alert-success">';
            output += '<h5>✅ No Changes Detected</h5>';
            output += '<table class="table table-sm"><thead><tr><th>Table</th><th>Hash</th><th>Record Count</th><th>Last Checked</th></tr></thead><tbody>';
            noChanges.forEach(item => {
                output += `<tr>
                    <td><strong>${item.table}</strong></td>
                    <td><code style="font-size: 10px;">${item.hash.substring(0, 16)}...</code></td>
                    <td>${item.recordCount}</td>
                    <td>${item.storedTimestamp || 'Unknown'}</td>
                </tr>`;
            });
            output += '</tbody></table></div>';
        }

        if (noStoredHash.length > 0) {
            output += '<div class="alert alert-info">';
            output += '<h5>ℹ️ No Previous Hash Found</h5>';
            output += '<p>Storing current hashes for future comparison:</p>';
            output += '<table class="table table-sm"><thead><tr><th>Table</th><th>Current Hash</th><th>Record Count</th></tr></thead><tbody>';
            noStoredHash.forEach(item => {
                output += `<tr>
                    <td><strong>${item.table}</strong></td>
                    <td><code style="font-size: 10px;">${item.currentHash.substring(0, 16)}...</code></td>
                    <td>${item.recordCount}</td>
                </tr>`;
            });
            output += '</tbody></table></div>';
        }

        // Store current hashes for future comparison
        selectedTables.forEach(tableName => {
            const currentData = window.DataHashes[tableName];
            localStorage.setItem(`dataHash_${tableName}`, currentData.hash);
            localStorage.setItem(`dataHashTimestamp_${tableName}`, currentData.timestamp);
        });

        output += '<p><small class="text-muted">Current hashes have been stored for future comparisons.</small></p>';
    }

    document.getElementById('changeOutput').innerHTML = output;
    document.getElementById('changeDetection').style.display = 'block';
}

function clearStoredHashes() {
    // Clear all stored hashes
    Object.keys(window.DataHashes).forEach(tableName => {
        localStorage.removeItem(`dataHash_${tableName}`);
        localStorage.removeItem(`dataHashTimestamp_${tableName}`);
    });

    document.getElementById('changeOutput').innerHTML = '<div class="alert alert-success">All stored hashes have been cleared.</div>';
    document.getElementById('changeDetection').style.display = 'block';

    console.log('All stored data hashes cleared from localStorage');
}

</script>

<style>
.card {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    background-color: #fff;
}

.card-header {
    padding: 0.75rem 1.25rem;
    margin-bottom: 0;
    background-color: #f8f9fa;
    border-bottom: 1px solid #dee2e6;
    border-top-left-radius: 0.375rem;
    border-top-right-radius: 0.375rem;
}

.card-body {
    padding: 1.25rem;
}

.btn {
    display: inline-block;
    padding: 0.375rem 0.75rem;
    margin-bottom: 0;
    font-size: 0.875rem;
    font-weight: 400;
    line-height: 1.5;
    text-align: center;
    white-space: nowrap;
    vertical-align: middle;
    cursor: pointer;
    border: 1px solid transparent;
    border-radius: 0.25rem;
    text-decoration: none;
}

.btn-primary {
    color: #fff;
    background-color: #007bff;
    border-color: #007bff;
}

.btn-secondary {
    color: #fff;
    background-color: #6c757d;
    border-color: #6c757d;
}

.btn-warning {
    color: #212529;
    background-color: #ffc107;
    border-color: #ffc107;
}

.btn:hover {
    opacity: 0.8;
}

.alert {
    padding: 0.75rem 1.25rem;
    margin-bottom: 1rem;
    border: 1px solid transparent;
    border-radius: 0.25rem;
}

.alert-success {
    color: #155724;
    background-color: #d4edda;
    border-color: #c3e6cb;
}

.alert-warning {
    color: #856404;
    background-color: #fff3cd;
    border-color: #ffeaa7;
}

.alert-info {
    color: #0c5460;
    background-color: #d1ecf1;
    border-color: #bee5eb;
}

.table-responsive {
    display: block;
    width: 100%;
    overflow-x: auto;
}

.table {
    width: 100%;
    margin-bottom: 1rem;
    color: #212529;
    border-collapse: collapse;
}

.table th,
.table td {
    padding: 0.5rem;
    vertical-align: top;
    border-top: 1px solid #dee2e6;
}

.table thead th {
    vertical-align: bottom;
    border-bottom: 2px solid #dee2e6;
    background-color: #f8f9fa;
}

.table-striped tbody tr:nth-of-type(odd) {
    background-color: rgba(0, 0, 0, 0.05);
}

.form-check {
    position: relative;
    display: block;
    padding-left: 1.25rem;
}

.form-check-input {
    position: absolute;
    margin-top: 0.3rem;
    margin-left: -1.25rem;
}

.form-check-label {
    margin-bottom: 0;
}
</style>
