        selectedTables.forEach(tableName => {
            const currentData = window.DataHashes[tableName];
            const storedHash = localStorage.getItem(`dataHash_${tableName}`);
            const storedTimestamp = localStorage.getItem(`dataHashTimestamp_${tableName}`);

            if (!storedHash) {
                noStoredHash.push({
                    table: tableName,
                    currentHash: currentData.hash,
                    recordCount: currentData.recordCount
                });
            } else if (storedHash !== currentData.hash) {
                changesDetected.push({
                    table: tableName,
                    currentHash: currentData.hash,
                    storedHash: storedHash,
                    currentCount: currentData.recordCount,
                    storedTimestamp: storedTimestamp
                });
            } else {
                noChanges.push({
                    table: tableName,
                    hash: currentData.hash,
                    recordCount: currentData.recordCount,
                    storedTimestamp: storedTimestamp
                });
            }
        });

        // Display results
        if (changesDetected.length > 0) {
            output += '<div class="alert alert-warning">';
            output += '<h5>⚠️ Changes Detected!</h5>';
            output += '<table class="table table-sm"><thead><tr><th>Table</th><th>Current Hash</th><th>Previous Hash</th><th>Current Count</th><th>Last Checked</th></tr></thead><tbody>';
            changesDetected.forEach(item => {
                output += `<tr>
                    <td><strong>${item.table}</strong></td>
                    <td><code style="font-size: 10px;">${item.currentHash.substring(0, 16)}...</code></td>
                    <td><code style="font-size: 10px;">${item.storedHash.substring(0, 16)}...</code></td>
                    <td>${item.currentCount}</td>
                    <td>${item.storedTimestamp || 'Unknown'}</td>
                </tr>`;
            });
            output += '</tbody></table></div>';
        }

        if (noChanges.length > 0) {
            output += '<div class="alert alert-success">';
            output += '<h5>✅ No Changes Detected</h5>';
            output += '<table class="table table-sm"><thead><tr><th>Table</th><th>Hash</th><th>Record Count</th><th>Last Checked</th></tr></thead><tbody>';
            noChanges.forEach(item => {
                output += `<tr>
                    <td><strong>${item.table}</strong></td>
                    <td><code style="font-size: 10px;">${item.hash.substring(0, 16)}...</code></td>
                    <td>${item.recordCount}</td>
                    <td>${item.storedTimestamp || 'Unknown'}</td>
                </tr>`;
            });
            output += '</tbody></table></div>';
        }

        if (noStoredHash.length > 0) {
            output += '<div class="alert alert-info">';
            output += '<h5>ℹ️ No Previous Hash Found</h5>';
            output += '<p>Storing current hashes for future comparison:</p>';
            output += '<table class="table table-sm"><thead><tr><th>Table</th><th>Current Hash</th><th>Record Count</th></tr></thead><tbody>';
            noStoredHash.forEach(item => {
                output += `<tr>
                    <td><strong>${item.table}</strong></td>
                    <td><code style="font-size: 10px;">${item.currentHash.substring(0, 16)}...</code></td>
                    <td>${item.recordCount}</td>
                </tr>`;
            });
            output += '</tbody></table></div>';
        }

        // Store current hashes for future comparison
        selectedTables.forEach(tableName => {
            const currentData = window.DataHashes[tableName];
            localStorage.setItem(`dataHash_${tableName}`, currentData.hash);
            localStorage.setItem(`dataHashTimestamp_${tableName}`, currentData.timestamp);
        });

        output += '<p><small class="text-muted">Current hashes have been stored for future comparisons.</small></p>';
    }

    document.getElementById('changeOutput').innerHTML = output;
    document.getElementById('changeDetection').style.display = 'block';
}

function clearStoredHashes() {
    // Clear all stored hashes
    Object.keys(window.DataHashes).forEach(tableName => {
        localStorage.removeItem(`dataHash_${tableName}`);
        localStorage.removeItem(`dataHashTimestamp_${tableName}`);
    });

    document.getElementById('changeOutput').innerHTML = '<div class="alert alert-success">All stored hashes have been cleared.</div>';
    document.getElementById('changeDetection').style.display = 'block';

    console.log('All stored data hashes cleared from localStorage');
}

</script>

